CREATE TABLE "User" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(100) NOT NULL,
    "LastName" character varying(100),
    "PhoneNumber" text,
    "Email" character varying(100) NOT NULL,
    "Password" text NOT NULL,
    "Salt" text NOT NULL,
    "LastAdvisDate" timestamp with time zone,
    "DeletedDate" timestamp with time zone,
    "Deleted" boolean NOT NULL,
    "DefaultUserStartPreference" text,
    "HasApiAccess" boolean,
    "HasStakeHolderAccess" boolean NOT NULL,
    "LockedOutDate" timestamp with time zone,
    "FailedAttempts" integer NOT NULL,
    "IsGlobalAdmin" boolean NOT NULL,
    "IsSystemIntegrator" boolean NOT NULL,
    "Uuid" uuid NOT NULL,
    "ObjectOwnerId" integer,
    "LastChanged" timestamp with time zone NOT NULL,
    "LastChangedByUserId" integer,
    CONSTRAINT "PK_User" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_User_User_LastChangedByUserId" FOREIGN KEY ("LastChangedByUserId") REFERENCES "User" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_User_User_ObjectOwnerId" FOREIGN KEY ("ObjectOwnerId") REFERENCES "User" ("Id") ON DELETE RESTRICT
);


